from abc import ABC, abstractmethod
from typing import Optional, List
from dataclasses import dataclass, field

@dataclass
class Product:
    """Complex object to be built."""
    parts: List[str] = field(default_factory=list)

    def add(self, part: str) -> None:
        self.parts.append(part)

    def list_parts(self) -> str:
        return f"Product parts: {', '.join(self.parts)}"

class Builder(ABC):
    """Builder interface."""

    @property
    @abstractmethod
    def product(self) -> Product:
        pass

    @abstractmethod
    def produce_part_a(self) -> None:
        pass

    @abstractmethod
    def produce_part_b(self) -> None:
        pass

    @abstractmethod
    def produce_part_c(self) -> None:
        pass

class ConcreteBuilder(Builder):
    """Concrete implementation of the Builder."""

    def __init__(self):
        self.reset()

    def reset(self) -> None:
        self._product = Product()

    @property
    def product(self) -> Product:
        product = self._product
        self.reset()
        return product

    def produce_part_a(self) -> None:
        self._product.add("PartA1")

    def produce_part_b(self) -> None:
        self._product.add("PartB1")

    def produce_part_c(self) -> None:
        self._product.add("PartC1")

class Director:
    """Director that orchestrates building."""

    def __init__(self):
        self._builder: Optional[Builder] = None

    @property
    def builder(self) -> Builder:
        return self._builder

    @builder.setter
    def builder(self, builder: Builder) -> None:
        self._builder = builder

    def build_minimal_product(self) -> None:
        self._builder.produce_part_a()

    def build_full_product(self) -> None:
        self._builder.produce_part_a()
        self._builder.produce_part_b()
        self._builder.produce_part_c()

